do {
    if let config: CarPlayConfig = try Current.database().read({ db in
        do {
            return try CarPlayConfig.fetchOne(db)
        } catch {
            Current.Log.error("Error fetching CarPlay config \(error)")
        }
        return nil
    }) {
        setConfig(config)
        Current.Log.info("CarPlay configuration exists")
    } else {
        Current.Log.info("No CarPlay config found, initializing default configuration")
        setConfig(CarPlayConfig())
    }
} catch {
    Current.Log.error("Failed to access database (GRDB), error: \(error.localizedDescription)")
    showError(message: L10n.Grdb.Config.MigrationError.failedAccessGrdb(error.localizedDescription))
}

switch state {
case let .disconnected(reason):
    switch reason {
    case let .waitingToReconnect(lastError: error, atLatest: atLatest, retryCount: count):
        var components = [String]()

        if let error {
            components.append(L10n.Settings.ConnectionSection.Websocket.Status.Disconnected.error(
                error.localizedDescription
            ))
        }

        components.append(L10n.Settings.ConnectionSection.Websocket.Status.Disconnected.retryCount(count))
        components.append(L10n.Settings.ConnectionSection.Websocket.Status.Disconnected.nextRetry(
            DateFormatter.localizedString(from: atLatest, dateStyle: .none, timeStyle: .medium)
        ))

        return components.joined(separator: "\n\n")
    case .disconnected:
        return L10n.Settings.ConnectionSection.Websocket.Status.Disconnected.title
    case .rejected:
        return L10n.Settings.ConnectionSection.Websocket.Status.Rejected.title
    }
default:
    return statusMessage
}

switch manager.status(for: server) {
case .disabled:
    localPushStatus = L10n.SettingsDetails.Notifications.LocalPush.Status.disabled
case .unsupported:
    localPushStatus = L10n.SettingsDetails.Notifications.LocalPush.Status.unsupported
case let .allowed(state):
    switch state {
    case .unavailable:
        localPushStatus = L10n.SettingsDetails.Notifications.LocalPush.Status.unavailable
    case .establishing:
        localPushStatus = L10n.SettingsDetails.Notifications.LocalPush.Status.establishing
    case let .available(received: received):
        let formatted = NumberFormatter.localizedString(
            from: NSNumber(value: received),
            number: .decimal
        )
        localPushStatus = L10n.SettingsDetails.Notifications.LocalPush.Status.available(formatted)
    }
}

if let magicItem, let magicItemInfo {
    displayText = magicItem.name(info: magicItemInfo)

    // Check if user has customized the icon color
    let customIconColor: UIColor? = {
        if let iconColorString = magicItem.customization?.iconColor {
            return UIColor(hex: iconColorString)
        }
        return nil
    }()

    let userHasCustomizedIcon = magicItem.customization?.iconIsCustomized == true
    if !entityHasDynamicIcon || userHasCustomizedIcon {
        // Use the configured icon, respecting any explicit user customization
        iconColor = customIconColor ?? .haPrimary
        image = magicItem.icon(info: magicItemInfo).carPlayIcon(color: iconColor)
    } else {
        // Dynamic entity icons should reflect the live server-provided color,
        // matching the main entities/controls views instead of saved quick-access tint.
        iconColor = entity.carPlayIconColor()
        image = entity.getMDI().carPlayIcon(color: iconColor)
    }
}

if let active = subController(for: notification, api: api) {
    activeSubController = active
} else {
    isLoading = true

    firstly {
        Current.notificationAttachmentManager.downloadAttachment(from: notification.request.content, api: api)
    }.tap { [self] result in
        if case .rejected = result {
            // we don't stop loading on success 'cause it's just gonna turn it on again
            isLoading = false
        }
    }.map { [self] url in
        subController(for: url, api: api)
    }.done { [self] controller in
        activeSubController = controller
    }.catch { [self] error in
        Current.Log.info("no attachments downloaded: \(error)")

        if error as? NotificationAttachmentManagerServiceError == .noAttachment {
            // can make the above != but it doesn't clearly indicate
        } else {
            show(error: error)
        }
    }
}

for item in items where itemFilter(item) {
    let serverId = item.serverId
    let entityId = item.id
    guard let domain = item.domain,
          let server = Current.servers.all.first(where: { $0.identifier.rawValue == serverId }) else { continue }

    if let state: ControlEntityProvider.State = await ControlEntityProvider(domains: [domain]).state(
        server: server,
        entityId: entityId
    ) {
        let value = stateValueFormatter(state, serverId, entityId)
        states[item] = .init(
            value: value,
            domainState: state.domainState,
            hexColor: state.color?.hex()
        )
    } else {
        Current.Log.error(
            "Failed to get state for entity in \(logPrefix) widget, entityId: \(entityId), serverId: \(serverId)"
        )
    }
}

do {
    guard var customWidgets = try CustomWidget.widgets(), !customWidgets.isEmpty else {
        return .result()
    }
    for index in customWidgets.indices {
        customWidgets[index].updateItemsStates([:])
    }

    do {
        try await Current.database().write { [customWidgets] db in
            for widget in customWidgets {
                do {
                    try widget.update(db)
                } catch {
                    Current.Log
                        .error(
                            "Failed to update custom widget to reset items states, error: \(error.localizedDescription)"
                        )
                }
            }
        }
    } catch {
        Current.Log
            .error("Failed to write custom widget to reset items states, error: \(error.localizedDescription)")
    }
} catch {
    Current.Log.error("Failed to load custom widgets to reset items states: \(error)")
}

for item in items {
    guard !item.isSeparator else {
        menu.addItem(.separator())
        continue
    }

    let menuItem = NSMenuItem(
        title: item.name,
        action: #selector(actionTapped(_:)),
        keyEquivalent: item.keyEquivalent
    )
    menu.addItem(menuItem)

    menuItem.keyEquivalentModifierMask = modifierKeys(for: item.keyEquivalentModifierMask)
    menuItem.target = self
    menuItem.representedObject = item

    if let image = item.image, case let imageSize = item.imageSize, imageSize != .zero {
        menuItem.image = NSImage(cgImage: image, size: imageSize)
    }

    if !item.subitems.isEmpty {
        menuItem.submenu = self.menu(for: item.subitems)
    }
}

if let pushID = Current.settingsStore.pushID {
    var appData: [String: Any] = [
        "push_url": AppConstants.Firebase.pushURLString,
        "push_token": pushID,
    ]

    #if os(iOS) && !targetEnvironment(macCatalyst)
    if #available(iOS 17.2, *) {
        // Push-to-start token (stored in Keychain at launch, updated via stream).
        // The relay server uses this token to start a Live Activity entirely via APNs.
        if let pushToStartToken = LiveActivityRegistry.storedPushToStartToken {
            appData["live_activity_token"] = pushToStartToken
            appData["live_activity_push_to_start_apns_environment"] = Current.apnsEnvironment
        }
    }
    #endif

    $0.AppData = appData
}

if
      let positionKeyframesX = transform.positionX?.keyframes,
      let positionKeyframesY = transform.positionY?.keyframes
    {
      let xPosition: NodeProperty<LottieVector1D> = NodeProperty(provider: KeyframeInterpolator(keyframes: positionKeyframesX))
      let yPosition: NodeProperty<LottieVector1D> = NodeProperty(provider: KeyframeInterpolator(keyframes: positionKeyframesY))
      propertyMap["X Position"] = xPosition
      propertyMap["Y Position"] = yPosition
      positionX = xPosition
      positionY = yPosition
      position = nil
    } else if let positionKeyframes = transform.position?.keyframes {
      let position: NodeProperty<LottieVector3D> = NodeProperty(provider: KeyframeInterpolator(keyframes: positionKeyframes))
      propertyMap[PropertyName.position.rawValue] = position
      self.position = position
      positionX = nil
      positionY = nil
    } else {
      position = nil
      positionY = nil
      positionX = nil
    }

if let decimalPlacesForEntityId: Int = {
    do {
        return try Current.database().read { db in
            try AppEntityRegistryListForDisplay
                .filter(
                    Column(DatabaseTables.AppEntityRegistryListForDisplay.id.rawValue) == ServerEntity
                        .uniqueId(
                            serverId: serverId,
                            entityId: entityId
                        )
                )
                .fetchOne(db)?.registry.decimalPlaces
        }
    } catch {
        Current.Log.error("Failed to fetch decimal places for entity ID: \(entityId)")
        return nil
    }
}() {
    return adjustPrecision(
        stateValue: stateValue,
        decimalPlaces: decimalPlacesForEntityId
    )
} else {
    return stateValue
}
